import os
import platform
import configparser
from pathlib import Path


def get_pip_config_path():
    """Get the appropriate pip configuration file path based on the operating system."""
    system = platform.system()
    
    if system == "Windows":
        # Windows: %APPDATA%\pip\pip.ini
        appdata = os.environ.get('APPDATA', os.path.expanduser('~\\AppData\\Roaming'))
        config_dir = Path(appdata) / 'pip'
        config_file = config_dir / 'pip.ini'
    else:
        # Linux/macOS: ~/.config/pip/pip.conf or ~/.pip/pip.conf
        config_dir = Path.home() / '.config' / 'pip'
        config_file = config_dir / 'pip.conf'
    
    return config_dir, config_file


def create_pip_config(
    internal_pypi_url="https://pypi.internal.company.com/simple",
    fallback_pypi_url="https://pypi.org/simple",
    trusted_hosts=None,
    timeout=60,
    retries=5,
    require_virtualenv=True,
    use_feature_truststore=True
):
    """
    Create a pip configuration file with secure settings.
    
    Args:
        internal_pypi_url: Internal PyPI mirror URL (must use HTTPS)
        fallback_pypi_url: Fallback PyPI URL (must use HTTPS)
        trusted_hosts: List of trusted hosts (only for internal networks with valid certs)
        timeout: Connection timeout in seconds
        retries: Number of retries for failed requests
        require_virtualenv: Require virtual environment for pip install
        use_feature_truststore: Use system certificate store (Python 3.10+)
    """
    
    # Security validation: Ensure URLs use HTTPS
    if not internal_pypi_url.startswith('https://'):
        raise ValueError("Internal PyPI URL must use HTTPS for security")
    if not fallback_pypi_url.startswith('https://'):
        raise ValueError("Fallback PyPI URL must use HTTPS for security")
    
    config_dir, config_file = get_pip_config_path()
    
    # Create config directory if it doesn't exist
    config_dir.mkdir(parents=True, exist_ok=True)
    
    # Create configuration parser
    config = configparser.ConfigParser()
    
    # [global] section - applies to all pip commands
    config['global'] = {
        'timeout': str(timeout),
        'retries': str(retries),
        'no-cache-dir': 'false',
        'disable-pip-version-check': 'false',
    }
    
    # Add trusted hosts only if specified (for internal networks with valid certificates)
    if trusted_hosts:
        # Only add trusted hosts if they match the internal URL domain
        validated_hosts = []
        for host in trusted_hosts:
            if host in internal_pypi_url:
                validated_hosts.append(host)
        if validated_hosts:
            config['global']['trusted-host'] = '\n' + '\n'.join(validated_hosts)
    
    # [install] section - applies to pip install
    config['install'] = {
        'index-url': internal_pypi_url,
        'extra-index-url': fallback_pypi_url,
        'prefer-binary': 'true',
    }
    
    # Require virtual environment for safety
    if require_virtualenv:
        config['install']['require-virtualenv'] = 'true'
    
    # Use system certificate store (Python 3.10+)
    if use_feature_truststore:
        config['install']['use-feature'] = 'truststore'
    
    # [list] section - applies to pip list
    config['list'] = {
        'format': 'columns',
    }
    
    # [freeze] section - applies to pip freeze
    config['freeze'] = {
        'timeout': str(timeout),
    }
    
    # Write configuration file
    with open(config_file, 'w') as f:
        config.write(f)
    
    # Set appropriate file permissions (read/write for owner only on Unix-like systems)
    if platform.system() != "Windows":
        os.chmod(config_file, 0o600)
    
    return config_file


def create_secure_pip_config_with_cert(
    internal_pypi_url="https://pypi.internal.company.com/simple",
    fallback_pypi_url="https://pypi.org/simple",
    cert_path=None,
    client_cert_path=None,
    timeout=60,
    retries=5
):
    """
    Create a pip configuration file with certificate-based authentication.
    
    Args:
        internal_pypi_url: Internal PyPI mirror URL (HTTPS)
        fallback_pypi_url: Fallback PyPI URL (HTTPS)
        cert_path: Path to CA certificate bundle for verification
        client_cert_path: Path to client certificate for mutual TLS
        timeout: Connection timeout in seconds
        retries: Number of retries for failed requests
    """
    
    # Security validation
    if not internal_pypi_url.startswith('https://'):
        raise ValueError("Internal PyPI URL must use HTTPS for security")
    if not fallback_pypi_url.startswith('https://'):
        raise ValueError("Fallback PyPI URL must use HTTPS for security")
    
    config_dir, config_file = get_pip_config_path()
    config_dir.mkdir(parents=True, exist_ok=True)
    
    config = configparser.ConfigParser()
    
    config['global'] = {
        'timeout': str(timeout),
        'retries': str(retries),
        'no-cache-dir': 'false',
    }
    
    # Add certificate verification
    if cert_path and os.path.exists(cert_path):
        config['global']['cert'] = cert_path
    
    # Add client certificate for mutual TLS
    if client_cert_path and os.path.exists(client_cert_path):
        config['global']['client-cert'] = client_cert_path
    
    config['install'] = {
        'index-url': internal_pypi_url,
        'extra-index-url': fallback_pypi_url,
        'prefer-binary': 'true',
        'require-virtualenv': 'true',
        'use-feature': 'truststore',
    }
    
    config['list'] = {
        'format': 'columns',
    }
    
    with open(config_file, 'w') as f:
        config.write(f)
    
    if platform.system() != "Windows":
        os.chmod(config_file, 0o600)
    
    return config_file


